#include <stdio.h>
#include <stdlib.h>
#include <cuda.h>

#include "../common.h"
#include "../util/timer/timer.h"

extern void setdevice(void);
extern void checkCUDAError(const char *msg);

__global__ void kernel_gpu(
    record *records,
    knode *knodes,
    long knodes_elem,
    int order,
    long maxheight,
    int count,
    long *currKnode,
    long *offset,
    int *keys,
    record *ans)
{
    int bid = blockIdx.x;
    int thid = threadIdx.x;

    if (bid >= count) return;

    long current_knode = currKnode[bid];
    long current_offset = offset[bid];
    int key_val = keys[bid];

    for (int i = 0; i < maxheight; i++) {
        if (thid < order + 1) {
            int k_val = knodes[current_knode].keys[thid];
            int k_next = knodes[current_knode].keys[thid + 1];

            if (k_val <= key_val && k_next > key_val) {
                if (knodes[current_offset].indices[thid] < knodes_elem) {
                    current_offset = knodes[current_offset].indices[thid];
                }
            }
        }
        current_knode = current_offset;
    }

    if (thid < order + 1) {
        if (knodes[current_knode].keys[thid] == key_val) {
            ans[bid].value = records[knodes[current_knode].indices[thid]].value;
        }
    }
}

void 
kernel_cpu(	int cores_arg,
			record *records,
			knode *knodes,
			long knodes_elem,
			int order,
			long maxheight,
			int count,
			long *currKnode,
			long *offset,
			int *keys,
			record *ans)
{
    long long time0;
    long long time1;
    long long time2;

    time0 = get_time();

    setdevice();

    int threadsPerBlock = order < 1024 ? order : 1024;
    int blocksPerGrid = count;

    record *d_records;
    knode *d_knodes;
    long *d_currKnode;
    long *d_offset;
    int *d_keys;
    record *d_ans;

    cudaMalloc(&d_records, count * sizeof(record)); 
    cudaMalloc(&d_knodes, knodes_elem * sizeof(knode));
    cudaMalloc(&d_currKnode, count * sizeof(long));
    cudaMalloc(&d_offset, count * sizeof(long));
    cudaMalloc(&d_keys, count * sizeof(int));
    cudaMalloc(&d_ans, count * sizeof(record));

    cudaMemcpy(d_knodes, knodes, knodes_elem * sizeof(knode), cudaMemcpyHostToDevice);
    cudaMemcpy(d_currKnode, currKnode, count * sizeof(long), cudaMemcpyHostToDevice);
    cudaMemcpy(d_offset, offset, count * sizeof(long), cudaMemcpyHostToDevice);
    cudaMemcpy(d_keys, keys, count * sizeof(int), cudaMemcpyHostToDevice);

    time1 = get_time();

    kernel_gpu<<<blocksPerGrid, threadsPerBlock>>>(
        d_records,
        d_knodes,
        knodes_elem,
        order,
        maxheight,
        count,
        d_currKnode,
        d_offset,
        d_keys,
        d_ans
    );

    checkCUDAError("kernel launch");
    cudaDeviceSynchronize();

    cudaMemcpy(ans, d_ans, count * sizeof(record), cudaMemcpyDeviceToHost);

    time2 = get_time();

    printf("Time spent in different stages of CPU/MCPU KERNEL:\n");
    printf("%15.12f s, %15.12f % : MCPU: SET DEVICE\n",					(float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time2-time0) * 100);
    printf("%15.12f s, %15.12f % : CPU/MCPU: KERNEL\n",					(float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time2-time0) * 100);

    printf("Total time:\n");
    printf("%.12f s\n", 												(float) (time2-time0) / 1000000);

    cudaFree(d_records);
    cudaFree(d_knodes);
    cudaFree(d_currKnode);
    cudaFree(d_offset);
    cudaFree(d_keys);
    cudaFree(d_ans);
}

