#include <stdio.h>
#include <stdlib.h>
#include <cuda.h>

#include "../common.h"
#include "../util/timer/timer.h"

extern void setdevice(void);
extern void checkCUDAError(const char *msg);

__global__ void kernel_gpu_2(
    knode *knodes,
    long knodes_elem,
    int order,
    long maxheight,
    int count,
    long *currKnode,
    long *offset,
    long *lastKnode,
    long *offset_2,
    int *start,
    int *end,
    int *recstart,
    int *reclength)
{
    int bid = blockIdx.x;
    int thid = threadIdx.x;

    if (bid >= count) return;

    long current_curr = currKnode[bid];
    long current_last = lastKnode[bid];
    long current_offset = offset[bid];
    long current_offset_2 = offset_2[bid];
    int start_val = start[bid];
    int end_val = end[bid];

    for (int i = 0; i < maxheight; i++) {
        if (thid < order + 1) {
            int k_val_curr = knodes[current_curr].keys[thid];
            int k_next_curr = knodes[current_curr].keys[thid + 1];

            if (k_val_curr <= start_val && k_next_curr > start_val) {
                if (knodes[current_curr].indices[thid] < knodes_elem) {
                    current_offset = knodes[current_curr].indices[thid];
                }
            }

            int k_val_last = knodes[current_last].keys[thid];
            int k_next_last = knodes[current_last].keys[thid + 1];

            if (k_val_last <= end_val && k_next_last > end_val) {
                if (knodes[current_last].indices[thid] < knodes_elem) {
                    current_offset_2 = knodes[current_last].indices[thid];
                }
            }
        }
        current_curr = current_offset;
        current_last = current_offset_2;
    }

    if (thid < order + 1) {
        if (knodes[current_curr].keys[thid] == start_val) {
            recstart[bid] = knodes[current_curr].indices[thid];
        }
    }

    if (thid < order + 1) {
        if (knodes[current_last].keys[thid] == end_val) {
            reclength[bid] = knodes[current_last].indices[thid] - recstart[bid] + 1;
        }
    }
}

