__global__ void kernel_cuda_2(
    knode *knodes,
    long knodes_elem,
    int order,
    long maxheight,
    int count,
    long *currKnode,
    long *offset,
    long *lastKnode,
    long *offset_2,
    int *start,
    int *end,
    int *recstart,
    int *reclength,
    int threadsPerBlock)
{
    int bid = blockIdx.x;
    if (bid >= count) return;

    int thid;
    long current_node = currKnode[bid];
    long last_node = lastKnode[bid];
    long offset_val = offset[bid];
    long offset_2_val = offset_2[bid];
    int start_val = start[bid];
    int end_val = end[bid];

    for (int i = 0; i < maxheight; i++) {
        for (thid = 0; thid < threadsPerBlock; thid++) {
            if (thid < order) {
                if ((knodes[current_node].keys[thid] <= start_val) && (knodes[current_node].keys[thid+1] > start_val)) {
                    if (knodes[current_node].indices[thid] < knodes_elem) {
                        offset_val = knodes[current_node].indices[thid];
                    }
                }
                if ((knodes[last_node].keys[thid] <= end_val) && (knodes[last_node].keys[thid+1] > end_val)) {
                    if (knodes[last_node].indices[thid] < knodes_elem) {
                        offset_2_val = knodes[last_node].indices[thid];
                    }
                }
            }
        }
        current_node = offset_val;
        last_node = offset_2_val;
    }

    for (thid = 0; thid < threadsPerBlock; thid++) {
        if (thid < order) {
            if (knodes[current_node].keys[thid] == start_val) {
                recstart[bid] = knodes[current_node].indices[thid];
            }
        }
    }

    for (thid = 0; thid < threadsPerBlock; thid++) {
        if (thid < order) {
            if (knodes[last_node].keys[thid] == end_val) {
                reclength[bid] = knodes[last_node].indices[thid] - recstart[bid] + 1;
            }
        }
    }
}

