__global__ void kernel_gpu(
    record *records,
    knode *knodes,
    long knodes_elem,
    int order,
    long maxheight,
    int count,
    long *currKnode,
    long *offset,
    int *keys,
    record *ans)
{
    int bid = blockIdx.x;
    int thid = threadIdx.x;

    if (bid >= count) return;

    long local_currKnode = currKnode[bid];
    long local_offset = offset[bid];
    int local_key = keys[bid];

    for (int i = 0; i < maxheight; i++) {
        if (thid < order + 1) {
            if ((knodes[local_currKnode].keys[thid] <= local_key) && (knodes[local_currKnode].keys[thid+1] > local_key)) {
                if (knodes[local_offset].indices[thid] < knodes_elem) {
                    local_offset = knodes[local_offset].indices[thid];
                }
            }
        }
        if (thid == 0) {
            currKnode[bid] = local_offset;
            local_currKnode = local_offset;
        }
    }

    if (thid < order + 1) {
        if (knodes[local_currKnode].keys[thid] == local_key) {
            ans[bid].value = records[knodes[local_currKnode].indices[thid]].value;
        }
    }
}

void 
kernel_cpu(	int cores_arg,
            record *records,
            knode *knodes,
            long knodes_elem,
            int order,
            long maxheight,
            int count,
            long *currKnode,
            long *offset,
            int *keys,
            record *ans)
{
    long long time0;
    long long time1;
    long long time2;

    time0 = get_time();

    setdevice();

    int threadsPerBlock = order < 1024 ? order + 1 : 1024;
    int numBlocks = count;

    record *d_records;
    knode *d_knodes;
    long *d_currKnode;
    long *d_offset;
    int *d_keys;
    record *d_ans;

    cudaMalloc(&d_records, count * sizeof(record)); 
    cudaMalloc(&d_knodes, knodes_elem * sizeof(knode));
    cudaMalloc(&d_currKnode, count * sizeof(long));
    cudaMalloc(&d_offset, count * sizeof(long));
    cudaMalloc(&d_keys, count * sizeof(int));
    cudaMalloc(&d_ans, count * sizeof(record));

    cudaMemcpy(d_knodes, knodes, knodes_elem * sizeof(knode), cudaMemcpyHostToDevice);
    cudaMemcpy(d_currKnode, currKnode, count * sizeof(long), cudaMemcpyHostToDevice);
