void 
list_init(	list_t *l,
            int32_t (*compare)(const void *key, 
            const void *with),
            void (*datum_delete)(void *))
{
  l->head = l->tail = NULL;
  l->length = 0;
  l->compare = compare;
  l->datum_delete = datum_delete;
}

void 
list_delete(list_t *l)
{
  list_item_t *li, *del;

  for (li = l->head; li;) {
    del = li;
    li = li->next;
    list_item_delete(del, l->datum_delete);
  }

  l->head = l->tail = NULL;
  l->length = 0;
}

void 
list_reset(list_t *l)
{
  list_delete(l);
}

void 
list_insert_item_head(	list_t *l, 
                        list_item_t *i)
{
  if (l->head) {
    i->next = l->head;
    l->head->pred = i;
    l->head = i;
    l->head->pred = NULL;
  } else {
    l->head = l->tail = i;
    i->next = i->pred = NULL;
  }
  l->length++;
}

void 
list_insert_item_tail(	list_t *l, 
                        list_item_t *i)
{
  if (l->head) {
    l->tail->next = i;
    i->pred = l->tail;
    i->next = NULL;
    l->tail = i;
  } else {
    l->head = l->tail = i;
    i->next = i->pred = NULL;
  }
  l->length++;
}

