  }

  for (i = 0; i < m; i++) {
    cudaMemcpy(new[i], d_data + i * n, n * sizeof(float), cudaMemcpyDeviceToHost);
  }

  cudaMemcpy(d_new, new, m * sizeof(float*), cudaMemcpyHostToDevice);

  for (i = 0; i < m; i++) {
