__global__ void computeTempKernel(float *pIn, float* tIn, float *tOut, 
        int nx, int ny, int nz, float Cap, 
        float Rx, float Ry, float Rz, 
        float dt, float ce, float cw, float cn, float cs, float ct, float cb, float cc) 
{
