#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>
#include <math.h>
#include <float.h>

#include "kmeans.h"

#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38
#endif

__device__ float euclid_dist_2_device(float *pt1, float *pt2, int numdims) {
    float ans = 0.0f;
    for (int i = 0; i < numdims; i++) {
        float diff = pt1[i] - pt2[i];
        ans += diff * diff;
    }
    return ans;
}

__device__ int find_nearest_point_device(float *pt, int nfeatures, float **pts, int npts) {
    int index = 0;
    float min_dist = FLT_MAX;

    for (int i = 0; i < npts; i++) {
        float dist = euclid_dist_2_device(pt, pts[i], nfeatures);
        if (dist < min_dist) {
            min_dist = dist;
            index = i;
        }
    }
    return index;
}

__global__ void kmeans_assign_clusters_kernel(float **feature, float **clusters, int *membership, 
                                              int npoints, int nclusters, int nfeatures, float *delta_ptr) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= npoints) return;

    int index = find_nearest_point_device(feature[i], nfeatures, clusters, nclusters);

    if (membership[i] != index) {
        *delta_ptr += 1.0f;
    }
    membership[i] = index;
}

__global__ void kmeans_update_centers_kernel(float **feature, int *membership, 
                                             float **partial_centers, int *partial_counts,
                                             int npoints, int nclusters, int nfeatures) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= npoints) return;

    int cluster_id = membership[i];
    int idx = cluster_id * nfeatures;

    for (int j = 0; j < nfeatures; j++) {
        partial_centers[idx + j] += feature[i][j];
    }
    partial_counts[cluster_id]++;
}

__global__ void kmeans_finalize_centers_kernel(float **clusters, float **partial_centers, int *partial_counts,
                                               int nclusters, int nfeatures, int nthreads) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= nclusters) return;

    float sum = 0.0f;
    int count = 0;

    for (int t = 0; t < nthreads; t++) {
        int base = t * nclusters;
        count += partial_counts[base + i];
        for (int k = 0; k < nfeatures; k++) {
            sum += partial_centers[(base + i) * nfeatures + k];
        }
    }

    if (count > 0) {
        for (int k = 0; k < nfeatures; k++) {
            clusters[i][k] = sum / count;
        }
    }

    for (int t = 0; t < nthreads; t++) {
        int base = t * nclusters;
        partial_counts[base + i] = 0;
        for (int k = 0; k < nfeatures; k++) {
            partial_centers[(base + i) * nfeatures + k] = 0.0f;
        }
    }
}

float** kmeans_clustering_cuda(float **feature, int nfeatures, int npoints, int nclusters, float threshold, int *membership) {
    int i, j, k;
    float **clusters;
    float *d_feature_flat;
    float *d_clusters_flat;
    int *d_membership;
    float *d_delta;
    float delta = 0.0f;
    int loop = 0;

    const int nthreads = 1; 
    int max_iter = 500;

    clusters = (float**) malloc(nclusters * sizeof(float*));
    clusters[0] = (float*) malloc(nclusters * nfeatures * sizeof(float));
    for (i = 1; i < nclusters; i++)
        clusters[i] = clusters[i-1] + nfeatures;

    int n = 0;
    for (i = 0; i < nclusters; i++) {
        for (j = 0; j < nfeatures; j++)
            clusters[i][j] = feature[n][j];
        n++;
    }

    for (i = 0; i < npoints; i++)
        membership[i] = -1;

    size_t feature_size = (size_t)npoints * nfeatures * sizeof(float);
    size_t clusters_size = (size_t)nclusters * nfeatures * sizeof(float);

    cudaMalloc(&d_feature_flat, feature_size);
    cudaMalloc(&d_clusters_flat, clusters_size);
    cudaMalloc(&d_membership, npoints * sizeof(int));
    cudaMalloc(&d_delta, sizeof(float));

    float *d_feature_row[npoints];
    float *d_clusters_row[nclusters];

    for(i=0; i<npoints; i++) d_feature_row[i] = d_feature_flat + i*nfeatures;
    for(i=0; i<nclusters; i++) d_clusters_row[i] = d_clusters_flat + i*nfeatures;

    cudaMemcpy(d_feature_flat, feature[0], feature_size, cudaMemcpyHostToDevice);
    cudaMemcpy(d_clusters_flat, clusters[0], clusters_size, cudaMemcpyHostToDevice);
    cudaMemcpy(d_membership, membership, npoints * sizeof(int), cudaMemcpyHostToDevice);

    int *partial_counts_host = (int*)calloc(nthreads * nclusters, sizeof(int));
    float *partial_centers_host = (float*)calloc(nthreads * nclusters * nfeatures, sizeof(float));

    int *d_partial_counts;
    float *d_partial_centers;

    size_t partial_counts_size = nthreads * nclusters * sizeof(int);
    size_t partial_centers_size = nthreads * nclusters * nfeatures * sizeof(float);

    cudaMalloc(&d_partial_counts, partial_counts_size);
    cudaMalloc(&d_partial_centers, partial_centers_size);
    cudaMemset(d_partial_counts, 0, partial_counts_size);
    cudaMemset(d_partial_centers, 0, partial_centers_size);

    int block_size = 256;
    int num_blocks_assign = (npoints + block_size - 1) / block_size;
    int num_blocks_update = (npoints + block_size - 1) / block_size;
    int num_blocks_final = (nclusters + block_size - 1) / block_size;

    do {
        delta = 0.0f;
        cudaMemcpy(d_delta, &delta, sizeof(float), cudaMemcpyHostToDevice);

        kmeans_assign_clusters_kernel<<<num_blocks_assign, block_size>>>(
            d_feature_row, d_clusters_row, d_membership, npoints, nclusters, nfeatures, d_delta);

        cudaMemset(d_partial_counts, 0, partial_counts_size);
        cudaMemset(d_partial_centers, 0, partial_centers_size);

        kmeans_update_centers_kernel<<<num_blocks_update, block_size>>>(
            d_feature_row, d_membership, d_partial_centers, d_partial_counts, npoints, nclusters, nfeatures);

        kmeans_finalize_centers_kernel<<<num_blocks_final, block_size>>>(
            d_clusters_row, d_partial_centers, d_partial_counts, nclusters, nfeatures, nthreads);

        cudaMemcpy(&delta, d_delta, sizeof(float), cudaMemcpyDeviceToHost);
        cudaMemcpy(clusters[0], d_clusters_flat, clusters_size, cudaMemcpyDeviceToHost);
        cudaMemcpy(membership, d_membership, npoints * sizeof(int), cudaMemcpyDeviceToHost);

    } while (delta > threshold && loop++ < max_iter);

    cudaFree(d_feature_flat);
    cudaFree(d_clusters_flat);
    cudaFree(d_membership);
    cudaFree(d_delta);
    cudaFree(d_partial_counts);
    cudaFree(d_partial_centers);
    free(partial_counts_host);
    free(partial_centers_host);

    return clusters;
}

int cluster(int numObjects, int numAttributes, float **attributes, int nclusters, float threshold, float ***cluster_centres) {
    int *membership;
    float **tmp_cluster_centres;

    membership = (int*) malloc(numObjects * sizeof(int));

    tmp_cluster_centres = kmeans_clustering_cuda(attributes, numAttributes, numObjects, nclusters, threshold, membership);

    if (*cluster_centres) {
        free((*cluster_centres)[0]);
        free(*cluster_centres);
    }
    *cluster_centres = tmp_cluster_centres;

    free(membership);

    return 0;
}

