                d.y = rA_i.y - rB_j.y;
                d.z = rA_i.z - rB_j.z;

                fp fxij = fs * d.x;
                fp fyij = fs * d.y;
                fp fzij = fs * d.z;

                fA_i.v += qB_j * vij;
                fA_i.x += qB_j * fxij;
                fA_i.y += qB_j * fyij;
                fA_i.z += qB_j * fzij;
            }
            fA[i] = fA_i;
        }
    }
