    long long time2 = get_time();
    long long time3 = get_time();

    fp alpha = par.alpha;
    fp a2 = 2.0 * alpha * alpha;

    time3 = get_time();

    box_str* box_d;
    FOUR_VECTOR* rv_d;
    fp* qv_d;
    FOUR_VECTOR* fv_d;

    cudaMalloc(&box_d, dim.box_mem);
    cudaMalloc(&rv_d, dim.space_mem);
    cudaMalloc(&qv_d, dim.space_mem2);
    cudaMalloc(&fv_d, dim.space_mem);

    cudaMemcpy(box_d, box, dim.box_mem, cudaMemcpyHostToDevice);
    cudaMemcpy(rv_d, rv, dim.space_mem, cudaMemcpyHostToDevice);
    cudaMemcpy(qv_d, qv, dim.space_mem2, cudaMemcpyHostToDevice);
    cudaMemcpy(fv_d, fv, dim.space_mem, cudaMemcpyHostToDevice);

    time2 = get_time();

    dim3 blockDim(NUMBER_PAR_PER_BOX, 1, 1);
    dim3 gridDim(dim.number_boxes, 1, 1);

    kernel_gpu<<<gridDim, blockDim>>>(par, dim, box_d, rv_d, qv_d, fv_d);

    cudaDeviceSynchronize();

    cudaMemcpy(fv, fv_d, dim.space_mem, cudaMemcpyDeviceToHost);

    long long time4 = get_time();

    printf("Time spent in different stages of GPU KERNEL:\n");
    printf("%15.12f s, %15.12f % : GPU: VARIABLES\n", (float)(time1-time0)/1000000, (float)(time1-time0)/(float)(time4-time0)*100);
    printf("%15.12f s, %15.12f % : GPU: SET DEVICE\n", (float)(time2-time1)/1000000, (float)(time2-time1)/(float)(time4-time0)*100);
    printf("%15.12f s, %15.12f % : GPU: INPUTS\n", (float)(time3-time2)/1000000, (float)(time3-time2)/(float)(time4-time0)*100);
    printf("%15.12f s, %15.12f % : GPU: KERNEL\n", (float)(time4-time3)/1000000, (float)(time4-time3)/(float)(time4-time0)*100);

    printf("Total time:\n");
    printf("%.12f s\n", (float)(time4-time0)/1000000);

    cudaFree(box_d);
    cudaFree(rv_d);
    cudaFree(qv_d);
    cudaFree(fv_d);
}

