                fp fs = 2.0 * vij;

                THREE_VECTOR d;
                d.x = rA[i].x - rB[j].x;
                d.y = rA[i].y - rB[j].y;
                d.z = rA[i].z - rB[j].z;

                fp fxij = fs * d.x;
                fp fyij = fs * d.y;
                fp fzij = fs * d.z;

                fA[i].v += qB[j] * vij;
                fA[i].x += qB[j] * fxij;
                fA[i].y += qB[j] * fyij;
                fA[i].z += qB[j] * fzij;
