		{
		  ctx->statistics.child_hist[i] += ctx->ref->h_child_hist[i];
        }

#endif

      stopTimer(fromboardtimer);
      ctx->statistics.t_match_coords_from_board += getTimerValue(fromboardtimer);
      deleteTimer(fromboardtimer);
   }

}


