	kat = kib;			
	kt42 = k42*33.5e-6/5;
	kt24 = k24;
	kat2 = kib;
	kt2a = kib*5;

	kcanCaoff = 1;			
	kcanCaon = kcanCaoff/0.5;							
	kcanCaM4on = 46;		
	kcanCaM4off = 0.0013;	
	kcanCaM2on = kcanCaM4on;
	kcanCaM2off = 2508*kcanCaM4off;
