__global__ void nw_block_kernel(int *input_itemsets, int *referrence, int max_rows, int max_cols, int penalty, int blk, int phase) {
    int b_index_x, b_index_y;

    if (phase == 0) {
        if (blk > (max_cols-1)/BLOCK_SIZE) return;
        int idx = blockIdx.x;
        if (idx >= blk) return;
        b_index_x = idx;
        b_index_y = blk - 1 - b_index_x;
    } else {
        int max_blk = (max_cols-1)/BLOCK_SIZE;
        if (blk > max_blk) return;
        int idx = blockIdx.x;
        int start_x = blk - 1;
        if (idx < start_x) return;
        if (idx >= max_blk) return;
        b_index_x = idx;
        b_index_y = max_blk + blk - 2 - b_index_x;
        if (b_index_y < 0 || b_index_y >= max_blk) return;
    }

    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    int base_ref_row = b_index_y * BLOCK_SIZE + 1;
    int base_ref_col = b_index_x * BLOCK_SIZE + 1;
    int base_in_row = b_index_y * BLOCK_SIZE;
    int base_in_col = b_index_x * BLOCK_SIZE;

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            reference_l[i * BLOCK_SIZE + j] = referrence[max_cols * (base_ref_row + i) + (base_ref_col + j)];
        }
    }

    for (int i = 0; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = input_itemsets[max_cols * (base_in_row + i) + (base_in_col + j)];
        }
    }

    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            int val_diag = input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + reference_l[(i - 1) * BLOCK_SIZE + j - 1];
            int val_left = input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty;
            int val_up = input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty;
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = maximum(val_diag, val_left, val_up);
        }
    }

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            input_itemsets[max_cols * (base_ref_row + i) + (base_ref_col + j)] = input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

void nw_optimized(int *input_itemsets, int *output_itemsets, int *referrence,
        int max_rows, int max_cols, int penalty) {

    int *d_input, *d_ref;
    size_t size = max_rows * max_cols * sizeof(int);

    cudaMalloc(&d_input, size);
    cudaMalloc(&d_ref, size);

    cudaMemcpy(d_input, input_itemsets, size, cudaMemcpyHostToDevice);
    cudaMemcpy(d_ref, referrence, size, cudaMemcpyHostToDevice);

    int max_blk = (max_cols - 1) / BLOCK_SIZE;

    printf("Processing top-left matrix\n");

    for (int blk = 1; blk <= max_blk; blk++) {
        int num_blocks = blk;
        nw_block_kernel<<<num_blocks, 1>>>(d_input, d_ref, max_rows, max_cols, penalty, blk, 0);
        cudaDeviceSynchronize();
    }

    printf("Processing bottom-right matrix\n");

    for (int blk = 2; blk <= max_blk; blk++) {
        int start_x = blk - 1;
        int num_blocks = max_blk - start_x;
        if (num_blocks > 0) {
            nw_block_kernel<<<num_blocks, 1>>>(d_input, d_ref, max_rows, max_cols, penalty, blk, 1);
            cudaDeviceSynchronize();
        }
    }

    cudaMemcpy(input_itemsets, d_input, size, cudaMemcpyDeviceToHost);

    cudaFree(d_input);
    cudaFree(d_ref);
}

