__global__ void speedy_init_kernel(Point *p, long k1, long k2, int dim) {
  for (long k = k1 + blockIdx.x; k < k2; k += blockDim.x * 1024) {
    float distance = dist(p[k], p[0], dim);
    p[k].cost = distance * p[k].weight;
    p[k].assign = 0;
  }
}

__global__ void speedy_worker_kernel(Point *p, long k1, long k2, int dim, int i, double *costs, int pid, int nproc) {
  double mytotal = 0;
  for (long k = k1 + blockIdx.x; k < k2; k += blockDim.x * 1024) {
    float distance = dist(p[i], p[k], dim);
    if (distance * p[k].weight < p[k].cost) {
      p[k].cost = distance * p[k].weight;
      p[k].assign = i;
    }
    mytotal += p[k].cost;
  }
  if (blockIdx.x == 0) {
    costs[pid] = mytotal;
  }
}

__global__ void speedy_master_kernel(Point *p, long num, long k1, long k2, int dim, float z, long *kcenter, bool *open_flag, int *i_ptr, double *costs, int nproc) {
  long local_kcenter = 0;
  int i = *i_ptr;

  if (blockIdx.x == 0) {
    while (i < num) {
      bool to_open = ((float)lrand48()/(float)INT_MAX) < (p[i].cost/z);
      if (to_open) {
        local_kcenter++;
        *open_flag = true;
        *i_ptr = i;
        break;
      }
      i++;
    }
    if (i >= num) {
      *open_flag = false;
      *i_ptr = num;
    }
  }

  if (*open_flag) {
    int curr_i = *i_ptr;
    for (long k = k1 + blockIdx.x; k < k2; k += blockDim.x * 1024) {
      float distance = dist(p[curr_i], p[k], dim);
      if (distance * p[k].weight < p[k].cost) {
        p[k].cost = distance * p[k].weight;
        p[k].assign = curr_i;
      }
    }
  }

  double mytotal = 0;
  for (long k = k1 + blockIdx.x; k < k2; k += blockDim.x * 1024) {
    mytotal += p[k].cost;
  }
  if (blockIdx.x == 0) {
    costs[nproc] = mytotal; 
    costs[nproc+1] = local_kcenter;
  }
}

float pspeedy(Points *points, float z, long *kcenter, int pid, void *barrier)
{
#ifdef PROFILE
  double t1 = gettime();
#endif

  long bsize = points->num/nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if( pid == nproc-1 ) k2 = points->num;

  static double totalcost;
  static bool open = false;
  static double* costs; 
  static int i_global;

#ifdef PRINTINFO
  if( pid == 0 ){
    fprintf(stderr, "Speedy: facility cost %lf\n", z);
  }
#endif

  if (pid == 0) {
    *kcenter = 1;
    costs = (double*)malloc(sizeof(double)*(nproc+2));
    i_global = 1;
    open = false;

    speedy_init_kernel<<<1, 256>>>(points->p, k1, k2, points->dim);
    cudaDeviceSynchronize();
  }

  if (pid != 0) {
    while(1) {
      if (i_global >= points->num) break;

      speedy_worker_kernel<<<1, 256>>>(points->p, k1, k2, points->dim, i_global, costs, pid, nproc);
      cudaDeviceSynchronize();

      if (pid == 0) {
        i_global++;
      }
    } 
  }
  else { 
    while(i_global < points->num) {
      bool to_open = ((float)lrand48()/(float)INT_MAX)<(points->p[i_global].cost/z);
      if( to_open )  {
        (*kcenter)++;
        open = true;

        speedy_master_kernel<<<1, 256>>>(points->p, points->num, k1, k2, points->dim, z, kcenter, &open, &i_global, costs, nproc);
        cudaDeviceSynchronize();

        open = false;
        i_global++;
      } else {
        i_global++;
      }
    }
    open = true;
  }

  open = false;

  double mytotal = 0;
  for( int k = k1; k < k2; k++ )  {
    mytotal += points->p[k].cost;
  }
  costs[pid] = mytotal;

  if( pid == 0 ) {
    totalcost=z*(*kcenter);
    for (int i = 0; i < nproc; i++) {
      totalcost += costs[i];
    } 
    free(costs);
  }

#ifdef PRINTINFO
  if( pid == 0 ) {
    fprintf(stderr, "Speedy opened %d facilities for total cost %lf\n", *kcenter, totalcost);
    fprintf(stderr, "Distance Cost %lf\n", totalcost - z*(*kcenter));
  }
#endif

#ifdef PROFILE
  double t2 = gettime();
  if( pid== 0 ) {
    time_speedy += t2 -t1;
  }
#endif
  return(totalcost);
}

__global__ void pgain_count_centers_kernel(bool *is_center, int *center_table, long k1, long k2, double *work_mem, int stride, int pid) {
  int count = 0;
  for (int i = k1 + blockIdx.x; i < k2; i += blockDim.x * 1024) {
    if (is_center[i]) {
      center_table[i] = count++;
    }
  }
  if (blockIdx.x == 0) {
    work_mem[pid*stride] = count;
  }
}

__global__ void pgain_update_table_kernel(bool *is_center, int *center_table, long k1, long k2, double *work_mem, int stride, int pid) {
  int offset = (int)work_mem[pid*stride];
  for (int i = k1 + blockIdx.x; i < k2; i += blockDim.x * 1024) {
    if (is_center[i]) {
      center_table[i] += offset;
    }
  }
}

__global__ void pgain_dist_kernel(Point *p, long k1, long k2, int dim, long x, bool *switch_membership, double *lower, int *center_table, float *cost_of_opening_x) {
  float local_cost = 0.0;
  for (int i = k1 + blockIdx.x; i < k2; i += blockDim.x * 1024) {
    float x_cost = dist(p[i], p[x], dim) * p[i].weight;
    float current_cost = p[i].cost;

    if (x_cost < current_cost) {
      switch_membership[i] = 1;
      local_cost += x_cost - current_cost;
    } else {
      int assign = p[i].assign;
      lower[center_table[assign]] += current_cost - x_cost;
    }
  }
  if (blockIdx.x == 0) {
    *cost_of_opening_x += local_cost;
  }
}

__global__ void pgain_close_kernel(bool *is_center, double *gl_lower, int *center_table, long k1, long k2, double z, int nproc, double *work_mem, int stride, int *number_of_centers_to_close, double *cost_of_opening_x) {
  double local_cost_adjust = 0.0;
  int local_count = 0;

  for (int i = k1 + blockIdx.x; i < k2; i += blockDim.x * 1024) {
    if (is_center[i]) {
      double low = z;
      int idx = center_table[i];
      for (int p = 0; p < nproc; p++) {
        low += work_mem[idx + p*stride];
      }
      gl_lower[idx] = low;

      if (low > 0) {
        local_count++;
        local_cost_adjust -= low;
      }
    }
  }

  if (blockIdx.x == 0) {
    *number_of_centers_to_close += local_count;
    *cost_of_opening_x += local_cost_adjust;
  }
}

__global__ void pgain_apply_kernel(Point *p, long k1, long k2, int dim, long x, bool *switch_membership, bool *is_center, double *gl_lower, int *center_table, bool *gl_cost_negative) {
  if (*gl_cost_negative) {
    for (int i = k1 + blockIdx.x; i < k2; i += blockDim.x * 1024) {
      bool close_center = gl_lower[center_table[p[i].assign]] > 0;
      if (switch_membership[i] || close_center) {
        p[i].cost = p[i].weight * dist(p[i], p[x], dim);
        p[i].assign = x;
      }
    }
    for (int i = k1 + blockIdx.x; i < k2; i += blockDim.x * 1024) {
      if (is_center[i] && gl_lower[center_table[i]] > 0) {
        is_center[i] = false;
      }
    }
    if (x >= k1 && x < k2) {
      is_center[x] = true;
    }
  }
}

double pgain(long x, Points *points, double z, long int *numcenters, int pid, void *barrier)
{
#ifdef PROFILE
  double t0 = gettime();
#endif

  long bsize = points->num/nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if( pid == nproc-1 ) k2 = points->num;

  int number_of_centers_to_close = 0;
  static double *work_mem;
  static double gl_cost_of_opening_x;
  static int gl_number_of_centers_to_close;

  int stride = *numcenters+2;
  int cl = CACHE_LINE/sizeof(double);
  if( stride % cl != 0 ) { 
    stride = cl * ( stride / cl + 1);
  }
  int K = stride -2;

  double cost_of_opening_x = 0;

  if( pid==0 ) { 
    work_mem = (double*) malloc(stride*(nproc+1)*sizeof(double));
    gl_cost_of_opening_x = 0;
    gl_number_of_centers_to_close = 0;
  }

  int count = 0;
  pgain_count_centers_kernel<<<1, 256>>>(is_center, center_table, k1, k2, work_mem, stride, pid);
  cudaDeviceSynchronize();

  if (pid == 0) {
    int accum = 0;
    for (int p = 0; p < nproc; p++) {
      int tmp = (int)work_mem[p*stride];
      work_mem[p*stride] = accum;
      accum += tmp;
    }
  }

  pgain_update_table_kernel<<<1, 256>>>(is_center, center_table, k1, k2, work_mem, stride, pid);
  cudaDeviceSynchronize();

  memset(switch_membership + k1, 0, (k2-k1)*sizeof(bool));
  memset(work_mem+pid*stride, 0, stride*sizeof(double));
  if( pid== 0 ) memset(work_mem+nproc*stride,0,stride*sizeof(double));

#ifdef PROFILE
  double t1 = gettime();
  if( pid == 0 ) time_gain_init += t1-t0;
#endif

  double* lower = &work_mem[pid*stride];
  double* gl_lower = &work_mem[nproc*stride];

  pgain_dist_kernel<<<1, 256>>>(points->p, k1, k2, points->dim, x, switch_membership, lower, center_table, &cost_of_opening_x);
  cudaDeviceSynchronize();

#ifdef PROFILE
  double t2 = gettime();
  if( pid==0){
    time_gain_dist += t2 - t1;
  }
#endif

  pgain_close_kernel<<<1, 256>>>(is_center, gl_lower, center_table, k1, k2, z, nproc, work_mem, stride, &number_of_centers_to_close, &cost_of_opening_x);
  cudaDeviceSynchronize();

  work_mem[pid*stride + K] = number_of_centers_to_close;
  work_mem[pid*stride + K+1] = cost_of_opening_x;

  if( pid==0 ) {
    gl_cost_of_opening_x = z;
    for( int p = 0; p < nproc; p++ ) {
      gl_number_of_centers_to_close += (int)work_mem[p*stride + K];
      gl_cost_of_opening_x += work_mem[p*stride+K+1];
    }
  }

  bool gl_cost_negative = (gl_cost_of_opening_x < 0);

  pgain_apply_kernel<<<1, 256>>>(points->p, k1, k2, points->dim, x, switch_membership, is_center, gl_lower, center_table, &gl_cost_negative);
  cudaDeviceSynchronize();

  if (gl_cost_negative) {
    if( pid==0 ) {
      *numcenters = *numcenters + 1 - gl_number_of_centers_to_close;
    }
  } else {
    if( pid==0 ) gl_cost_of_opening_x = 0;  
  }

  if( pid == 0 ) {
    free(work_mem);
  }

#ifdef PROFILE
  double t3 = gettime();
  if( pid==0 ) time_gain += t3-t0;
#endif

  return -gl_cost_of_opening_x;
}

float pFL(Points *points, int *feasible, int numfeasible, float z, long *k, double cost, long iter, float e, int pid, void *barrier)
{
#ifdef PROFILE
  double t0 = gettime();
#endif
  long i;
  long x;
  double change;
  long numberOfPoints;

  change = cost;

  while (change/cost > 1.0*e) {
    change = 0.0;
    numberOfPoints = points->num;

    if( pid == 0 ) {
      intshuffle(feasible, numfeasible);
    }

    for (i=0;i<iter;i++) {
      x = i%numfeasible;
      change += pgain(feasible[x], points, z, k, pid, barrier);
    }

    cost -= change;
#ifdef PRINTINFO
    if( pid == 0 ) {
      fprintf(stderr, "%d centers, cost %lf, total distance %lf\n", *k, cost, cost - z*(*k));
    }
#endif
  }
#ifdef PROFILE
  double t1 = gettime();
  if (pid == 0) time_local_search += t1 - t0;
#endif
  return(cost);
}

int selectfeasible_fast(Points *points, int **feasible, int kmin, int pid, void *barrier)
{
#ifdef PROFILE
  double t1 = gettime();
#endif

  int numfeasible = points->num;
  if (numfeasible > (ITER*kmin*log((double)kmin)))
    numfeasible = (int)(ITER*kmin*log((double)kmin));
  *feasible = (int *)malloc(numfeasible*sizeof(int));

  float* accumweight;
  float totalweight;

  long k1 = 0;
  long k2 = numfeasible;

  float w;
  int l,r,k;

  if (numfeasible == points->num) {
    for (int i=k1;i<k2;i++)
      (*feasible)[i] = i;
#ifdef PROFILE
    double t2 = gettime();
    time_select_feasible += t2-t1;
#endif
    return numfeasible;
  }

  accumweight= (float*)malloc(sizeof(float)*points->num);
  accumweight[0] = points->p[0].weight;
  totalweight=0;
  for( int i = 1; i < points->num; i++ ) {
    accumweight[i] = accumweight[i-1] + points->p[i].weight;
  }
  totalweight=accumweight[points->num-1];

  for(int i=k1; i<k2; i++ ) {
    w = (lrand48()/(float)INT_MAX)*totalweight;
    l=0;
    r=points->num-1;
    if( accumweight[0] > w ) { 
      (*feasible)[i]=0; 
      continue;
    }
    while( l+1 < r ) {
      k = (l+r)/2;
      if( accumweight[k] > w ) {
        r = k;
      } else {
        l=k;
      }
    }
    (*feasible)[i]=r;
  }

  free(accumweight); 

#ifdef PROFILE
  double t2 = gettime();
  time_select_feasible += t2-t1;
#endif
  return numfeasible;
}

float pkmedian(Points *points, long kmin, long kmax, long* kfinal, int pid, void *barrier )
{
  int i;
  double cost;
  double lastcost;
  double hiz, loz, z;

  static long k;
  static int *feasible;
  static int numfeasible;
  static double* hizs;

  if( pid==0 ) hizs = (double*)calloc(nproc,sizeof(double));
  hiz = loz = 0.0;
  long numberOfPoints = points->num;
  long ptDimension = points->dim;

  long bsize = points->num/nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if( pid == nproc-1 ) k2 = points->num;

#ifdef PRINTINFO
  if( pid == 0 ) {
    printf("Starting Kmedian procedure\n");
    printf("%i points in %i dimensions\n", numberOfPoints, ptDimension);
  }
#endif

  double myhiz = 0;
  for (long kk=k1;kk < k2; kk++ ) {
    myhiz += dist(points->p[kk], points->p[0], ptDimension)*points->p[kk].weight;
  }
  hizs[pid] = myhiz;

  for( int i = 0; i < nproc; i++ ) {
    hiz += hizs[i];
  }

  loz=0.0; z = (hiz+loz)/2.0;

  if (points->num <= kmax) {
    for (long kk=k1;kk<k2;kk++) {
      points->p[kk].assign = kk;
      points->p[kk].cost = 0;
    }
    cost = 0;
    if( pid== 0 ) {
      free(hizs); 
      *kfinal = k;
    }
    return cost;
  }

  if( pid == 0 ) shuffle(points);
  cost = pspeedy(points, z, &k, pid, barrier);

#ifdef PRINTINFO
  if( pid == 0 )
    printf("thread %d: Finished first call to speedy, cost=%lf, k=%i\n",pid,cost,k);
#endif
  i=0;

  while ((k < kmin)&&(i<SP)) {
    cost = pspeedy(points, z, &k, pid, barrier);
    i++;
  }

#ifdef PRINTINFO
  if( pid==0)
    printf("thread %d: second call to speedy, cost=%lf, k=%d\n",pid,cost,k);
#endif 

  while (k < kmin) {
#ifdef PRINTINFO
    if( pid == 0 ) {
      printf("%lf %lf\n", loz, hiz);
      printf("Speedy indicates we should try lower z\n");
    }
#endif
    if (i >= SP) {hiz=z; z=(hiz+loz)/2.0; i=0;}
    if( pid == 0 ) shuffle(points);
    cost = pspeedy(points, z, &k, pid, barrier);
    i++;
  }

  if( pid == 0 ) {
    numfeasible = selectfeasible_fast(points,&feasible,kmin,pid,barrier);
    for( int i = 0; i< points->num; i++ ) {
      is_center[points->p[i].assign]= true;
    }
  }

  while(1) {
#ifdef PRINTINFO
    if( pid==0 ) {
      printf("loz = %lf, hiz = %lf\n", loz, hiz);
      printf("Running Local Search...\n");
    }
#endif

    lastcost = cost;
    cost = pFL(points, feasible, numfeasible, z, &k, cost, (long)(ITER*kmax*log((double)kmax)), 0.1, pid, barrier);

    if (((k <= (1.1)*kmax)&&(k >= (0.9)*kmin))||((k <= kmax+2)&&(k >= kmin-2))) {
#ifdef PRINTINFO
      if( pid== 0) {
        printf("Trying a more accurate local search...\n");
      }
#endif
      cost = pFL(points, feasible, numfeasible, z, &k, cost, (long)(ITER*kmax*log((double)kmax)), 0.001, pid, barrier);
    }

    if (k > kmax) {
      loz = z; z = (hiz+loz)/2.0;
      cost += (z-loz)*k;
    }
    if (k < kmin) {
      hiz = z; z = (hiz+loz)/2.0;
      cost += (z-hiz)*k;
    }

    if (((k <= kmax)&&(k >= kmin))||((loz >= (0.999)*hiz)) ) { 
      break;
    }
  }

  if( pid==0 ) {
    free(feasible); 
    free(hizs);
    *kfinal = k;
  }

  return cost;
}

int contcenters(Points *points)
{
  long i, ii;
  float relweight;

  for (i=0;i<points->num;i++) {
    if (points->p[i].assign != i) {
      relweight=points->p[points->p[i].assign].weight + points->p[i].weight;
      relweight = points->p[i].weight/relweight;
      for (ii=0;ii<points->dim;ii++) {
        points->p[points->p[i].assign].coord[ii]*=1.0-relweight;
        points->p[points->p[i].assign].coord[ii]+= points->p[i].coord[ii]*relweight;
      }
      points->p[points->p[i].assign].weight += points->p[i].weight;
    }
  }
  return 0;
}

void copycenters(Points *points, Points* centers, long* centerIDs, long offset)
{
  long i;
  long k;

  bool *is_a_median = (bool *) calloc(points->num, sizeof(bool));

  for ( i = 0; i < points->num; i++ ) {
    is_a_median[points->p[i].assign] = 1;
  }

  k=centers->num;

  for ( i = 0; i < points->num; i++ ) {
    if ( is_a_median[i] ) {
      memcpy( centers->p[k].coord, points->p[i].coord, points->dim * sizeof(float));
      centers->p[k].weight = points->p[i].weight;
      centerIDs[k] = i + offset;
      k++;
    }
  }

  centers->num = k;
  free(is_a_median);
}

struct pkmedian_arg_t
{
  Points* points;
  long kmin;
  long kmax;
  long* kfinal;
  int pid;
  void* barrier;
};

void* localSearchSub(void* arg_) {
  pkmedian_arg_t* arg= (pkmedian_arg_t*)arg_;
  pkmedian(arg->points,arg->kmin,arg->kmax,arg->kfinal,arg->pid,arg->barrier);
  return NULL;
}

void localSearch( Points* points, long kmin, long kmax, long* kfinal ) {
#ifdef PROFILE
  double t1 = gettime();
#endif

  pkmedian_arg_t arg;
  arg.points = points;
  arg.kmin = kmin;
  arg.kmax = kmax;
  arg.pid = 0;
  arg.kfinal = kfinal;
  arg.barrier = NULL;

  localSearchSub(&arg);

#ifdef PROFILE
  double t2 = gettime();
  time_local_search += t2-t1;
#endif
}

class PStream {
public:
  virtual size_t read( float* dest, int dim, int num ) = 0;
  virtual int ferror() = 0;
  virtual int feof() = 0;
  virtual ~PStream() {}
};

class SimStream : public PStream {
public:
  SimStream(long n_ ) { n = n_; }
  size_t read( float* dest, int dim, int num ) {
    size_t count = 0;
    for( int i = 0; i < num && n > 0; i++ ) {
      for( int k = 0; k < dim; k++ ) {
        dest[i*dim + k] = lrand48()/(float)INT_MAX;
      }
      n--;
      count++;
    }
    return count;
  }
  int ferror() { return 0; }
  int feof() { return n <= 0; }
  ~SimStream() {}
private:
  long n;
};

class FileStream : public PStream {
public:
  FileStream(char* filename) {
    fp = fopen( filename, "rb");
    if( fp == NULL ) {
      fprintf(stderr,"error opening file %s\n.",filename);
      exit(1);
    }
  }
  size_t read( float* dest, int dim, int num ) {
    return std::fread(dest, sizeof(float)*dim, num, fp); 
  }
  int ferror() { return std::ferror(fp); }
  int feof() { return std::feof(fp); }
  ~FileStream() {
    printf("closing file stream\n");
    fclose(fp);
  }
private:
  FILE* fp;
};

void outcenterIDs( Points* centers, long* centerIDs, char* outfile ) {
  FILE* fp = fopen(outfile, "w");
  if( fp==NULL ) {
    fprintf(stderr, "error opening %s\n",outfile);
    exit(1);
  }
  int* is_a_median = (int*)calloc( sizeof(int), centers->num );
  for( int i =0 ; i< centers->num; i++ ) {
    is_a_median[centers->p[i].assign] = 1;
  }

  for( int i = 0; i < centers->num; i++ ) {
    if ( is_a_median[i] ) {
      fprintf(fp, "%u\n", centerIDs[i]);
      fprintf(fp, "%lf\n", centers->p[i].weight);
      for ( int k = 0; k < centers->dim; k++ ) {
        fprintf(fp, "%lf ", centers->p[i].coord[k]);
      }
      fprintf(fp,"\n\n");
    }
  }
  fclose(fp);
}

void streamCluster( PStream* stream, long kmin, long kmax, int dim, long chunksize, long centersize, char* outfile )
{
  float* block = (float*)malloc( chunksize*dim*sizeof(float) );
  float* centerBlock = (float*)malloc(centersize*dim*sizeof(float) );
  long* centerIDs = (long*)malloc(centersize*dim*sizeof(long));

  if( block == NULL ) { 
    fprintf(stderr,"not enough memory for a chunk!\n");
    exit(1);
  }

  Points points;
  points.dim = dim;
  points.num = chunksize;
  points.p = (Point *)malloc(chunksize*sizeof(Point));
  for( int i = 0; i < chunksize; i++ ) {		
    points.p[i].coord = &block[i*dim];
  }

  Points centers;
  centers.dim = dim;
  centers.p = (Point *)malloc(centersize*sizeof(Point));
  centers.num = 0;

  for( int i = 0; i< centersize; i++ ) {
    centers.p[i].coord = &centerBlock[i*dim];
    centers.p[i].weight = 1.0;
  }

  long IDoffset = 0;
  long kfinal;
  while(1) {
    size_t numRead  = stream->read(block, dim, chunksize ); 
    fprintf(stderr,"read %d points\n",numRead);

    if( stream->ferror() || numRead < (unsigned int)chunksize && !stream->feof() ) {
      fprintf(stderr, "error reading data!\n");
      exit(1);
    }

    points.num = numRead;
    for( int i = 0; i < points.num; i++ ) {
      points.p[i].weight = 1.0;
    }

    switch_membership = (bool*)malloc(points.num*sizeof(bool));
    is_center = (bool*)calloc(points.num,sizeof(bool));
    center_table = (int*)malloc(points.num*sizeof(int));

    localSearch(&points,kmin, kmax,&kfinal);

    fprintf(stderr,"finish local search\n");
    contcenters(&points);
    if( kfinal + centers.num > centersize ) {
      fprintf(stderr,"oops! no more space for centers\n");
      exit(1);
    }

#ifdef PRINTINFO
    printf("finish cont center\n");
#endif

    copycenters(&points, &centers, centerIDs, IDoffset);
    IDoffset += numRead;

#ifdef PRINTINFO
    printf("finish copy centers\n"); 
#endif

    free(is_center);
    free(switch_membership);
    free(center_table);

    if( stream->feof() ) {
      break;
    }
  }

  switch_membership = (bool*)malloc(centers.num*sizeof(bool));
  is_center = (bool*)calloc(centers.num,sizeof(bool));
  center_table = (int*)malloc(centers.num*sizeof(int));

  localSearch( &centers, kmin, kmax ,&kfinal );
  contcenters(&centers);
  outcenterIDs( &centers, centerIDs, outfile);
}

int main(int argc, char **argv)
{
  char *outfilename = new char[MAXNAMESIZE];
  char *infilename = new char[MAXNAMESIZE];
  long kmin, kmax, n, chunksize, clustersize;
  int dim;

#ifdef PARSEC_VERSION
#define __PARSEC_STRING(x) #x
#define __PARSEC_XSTRING(x) __PARSEC_STRING(x)
  printf("PARSEC Benchmark Suite Version "__PARSEC_XSTRING(PARSEC_VERSION)"\n");
  fflush(NULL);
#else
  printf("PARSEC Benchmark Suite\n");
  fflush(NULL);
#endif 

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_bench_begin(__parsec_streamcluster);
#endif

  if (argc<10) {
    fprintf(stderr,"usage: %s k1 k2 d n chunksize clustersize infile outfile nproc\n", argv[0]);
    fprintf(stderr,"  k1:          Min. number of centers allowed\n");
    fprintf(stderr,"  k2:          Max. number of centers allowed\n");
    fprintf(stderr,"  d:           Dimension of each data point\n");
    fprintf(stderr,"  n:           Number of data points\n");
    fprintf(stderr,"  chunksize:   Number of data points to handle per step\n");
    fprintf(stderr,"  clustersize: Maximum number of intermediate centers\n");
    fprintf(stderr,"  infile:      Input file (if n<=0)\n");
    fprintf(stderr,"  outfile:     Output file\n");
    fprintf(stderr,"  nproc:       Number of threads to use\n");
    fprintf(stderr,"\n");
    fprintf(stderr, "if n > 0, points will be randomly generated instead of reading from infile.\n");
    exit(1);
  }
  kmin = atoi(argv[1]);
  kmax = atoi(argv[2]);
  dim = atoi(argv[3]);
  n = atoi(argv[4]);
  chunksize = atoi(argv[5]);
  clustersize = atoi(argv[6]);
  strcpy(infilename, argv[7]);
  strcpy(outfilename, argv[8]);
  nproc = atoi(argv[9]);

  srand48(SEED);
  PStream* stream;
  if( n > 0 ) {
    stream = new SimStream(n);
  }
  else {
    stream = new FileStream(infilename);
  }

  double t1 = gettime();

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_begin();
#endif
  streamCluster(stream, kmin, kmax, dim, chunksize, clustersize, outfilename );
#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_end();
#endif

  double t2 = gettime();

  printf("time = %lf\n",t2-t1);

